    BEAM_HIGHLIGHT_THRESHOLD_LOW,
    BEAM_HIGHLIGHT_THRESHOLD_HIGH,
    accumulatedHighlight +
    luminance * BEAM_HIGHLIGHT_LUMA_GAIN
